const frmNm = "data_frm_N400"


let flds = [
	"someone_help_preparing", 
	"family_help_preparing", 
	"counsel_provider_list",
	"documentType",


	"political_AB", 
	"political_BB",
	"political_2B",  
	"political_4B"
]





const GenerateN400  = ({ data,  confirm }) => {


	const [initialize, setInitialize] = useState(false);
	const [obs, set_obs] = useState(0);


	
	useEffect(() => {
		if (!initialize) {
			
			setInitialize(true);
			set_obs(gen16CodeId());

			setTimeout(() => {
				updFrm("documentType", "N400");
				set_obs(gen16CodeId())
				if(!getStore("N400_form.pdf")){

					loadPdfModel("N400_form.pdf");
				}
			}, 50);
			return () => {
				//updStore(frmNm, null);
			}; 
		}
	});




	const refresh = (ii) => {
		set_obs(gen16CodeId())
	}

	const loadPdfModel = (ii) => {
		let lastTimeCallModal = getStore("N400Pdf_last") || 0;
		if(Date.now() > lastTimeCallModal){
			updStore("N400Pdf_last", Date.now()+490);
			loadUrlByMT(ii, refresh);
		}
	}

	const updFrm = (f, v) => {
		let frm2 = getStore(frmNm) || {};
		frm2[f] = v;
		updStore(frmNm, frm2);
		set_obs(gen16CodeId())
	};



	const save  = async ()  => {

		let ffm =  getStore(frmNm);

		let bdyq2 = {};
		if(ffm["caseId"]){
			
			let diff = compareJSON(flds, ffm, getStore(frmNm + "_bck") )

			bdyq2 = {...getStore(qryStore())?.upd_notry_case};
			bdyq2.params = {
				customerId: getStore(qryKClient())?.clientNotaryId,
				"caseId": ffm["caseId"]
			};
			bdyq2.data2update = diff.data;
		}
		else{
			ffm["customerId"] = getStore(qryKClient()).clientNotaryId;
			ffm["documentType"] = "N400";
			ffm["caseId"] = gen16CodeId();
			
			if(!ffm["date"]){
				ffm["date"] = (new Date()).getTime()+800;
			}
			else{
				ffm["date"] =(new Date(ffm["date"])).getTime();
			}
			
			bdyq2 = {...getStore(qryStore())?.add_notry_case};
			bdyq2.params = {
				customerId: getStore(qryKClient())?.clientNotaryId
			};
			bdyq2.form = ffm;
		}

		// * Class B Automovile (Mar 2010), C: Truck over 7500KG (Jun 2014)
	
		const res = fetchEncryptStream(bdyq2);
		const td = await res;
		
		if (td && !td.error) {
			close();
		}
	}




	const print  = async ()  => {

		let user = {...getStore(qryKClient())};
		let N400_data = getStore(frmNm);
		let uu = Object.assign( {},user, N400_data );

		let ffm = preparN400(uu);
		
		// let N400_struct = getStore("print_structure")?.N400_details_struct_print || {};



		

		let pdfUri = await generateN400PDf(ffm,  N400_struct, true, true);
		window.open(pdfUri);
	}


	const close  = ()  => {
		data?.modalID && CloseModal({id:data?.modalID});
	}
	
	let validSv = compareJSON(flds,getStore(frmNm),getStore(frmNm + "_bck") )
	



	return(
		<div style={{
			maxHeight: "80vh",
			width: "820px",
			overflow: "auto",
			background: "var(--dark-800)",
			borderRadius: 13,
			padding: "10px 19px"
		}}>
			<div className="_dsplFlx ">
				<p className="form_title">
					N-400
				</p>
				<div className="flexSpace"/>
				<div className="card">
					{getStore("N400_form.pdf")?
						<GrayButton label={"Imprimir"} clickHandler={print}/>
					:null}
				</div>
			</div>
			
			
			

		
			<div className="_dsplFlx spaceAround flxWrp" style={{margin:"30px 0px 0 0"}}>
					
			<div className="_dsplFlx " style={{marginTop: 20}}>
					<CheckBoxSlide
						initvalue={getStore(frmNm)?.["counsel_provider_list"]}
						keyCode={57}
						updChange={(e)=>updFrm("counsel_provider_list",e)}
					/>
					<span className={`checklabel`}>
						{"Counselor List"}
					</span>
				</div>
				
				<div className="_dsplFlx " style={{marginTop: 20}}>
					<CheckBoxSlide
						initvalue={getStore(frmNm)?.["family_help_preparing"]}
						keyCode={35}
						updChange={(e)=>updFrm("family_help_preparing",e)}
					/>
					<span className={`checklabel`}>
						{"Family Helping"}
					</span>
				</div>

				<div className="_dsplFlx " style={{marginTop: 20}}>
					<CheckBoxSlide
						initvalue={getStore(frmNm)?.["someone_help_preparing"]}
						keyCode={39}
						updChange={(e)=>updFrm("someone_help_preparing",e)}
					/>
					<span className={`checklabel`}>
						{"Someone preparing"}
					</span>
				</div>
			</div>
			
			<div className="_dsplFlx spaceAround"  style={{marginTop:20}}> 
			
			</div>
			<div className="_dsplFlx spaceAround flxWrp"> 
				<TextAreaHRM  
					init={getStore(frmNm)?.["political_AB"]} 
					label={"¿Usted, su familia, amigos cercanos o colegas alguna vez han sufrido daños, malos tratos o amenazas en el pasado por parte de alguien?"} 
					width={"760px"} 
					updChanges={(e)=>updFrm("political_AB",e)}
				/>
				<TextAreaHRM  
					init={getStore(frmNm)?.["political_BB"]} 
					label={"¿Temes daño o maltrato si regresas a tu país de origen?"} 
					width={"760px"} 
					updChanges={(e)=>updFrm("political_BB",e)}
				/>
				<TextAreaHRM  
					init={getStore(frmNm)?.["political_2B"]} 
					label={"¿Tiene miedo de ser torturado en su país de origen o en cualquier otro país al que pueda ser devuelto?"} 
					width={"760px"} 
					updChanges={(e)=>updFrm("political_2B",e)}
				/>
				<TextAreaHRM  
					init={getStore(frmNm)?.["political_4B"]} 
					label={"Después de salir del país del que solicita asilo, usted o su cónyuge o hijo(s) que ahora están en los Estados Unidos, ¿viajaron o residieron en algún otro país antes de ingresar a los Estados Unidos?, el nombre de cada país y la duración de la estadía solicitó la condición de refugiado. o para asilo mientras estuvo allí, y si no, por qué él o ella no lo hizo.?"} 
					width={"760px"} 
					updChanges={(e)=>updFrm("political_4B",e)}
				/>

			</div> 
			
			<div className="_dsplFlx spaceAround" style={{marginTop:20}}>
				<DateCalComponent  
					init={getStore(frmNm)?.["translateDate"]} 
					label={"Fecha de la traduccion"}
					updDate={(e)=>updFrm("translateDate",e)}
				/>
			</div>
			<div className="_dsplFlx spaceAround" style={{marginTop:20}}>
			
			{validSv?.hasChange ? (
				<div className="_dsplFlx ">
					<div className="flexSpace"/>
					<div className="card">
						<GrayButton label={getStore(frmNm)?.["caseId"]?"Actualizar":"Agregar"} clickHandler={save}/>
						
					</div>
				</div>
			):<div className="card"/>}
		
			</div>
		</div>
	)

}



export default GenerateN400;








